#include <iostream>
#include <vector>

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    bool isCycle(ListNode* head) {
        if (!head) return false;
        ListNode* slow = head;
        ListNode* fast = head;
        while (slow && fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
            if (slow == fast) return true;
        }
        return false;
    }
};

int main() {
    // Create a test case
    ListNode node1(1);
    ListNode node2(2);
    node1.next = &node2;
    node2.next = &node2;
    Solution s;
    std::cout << std::boolalpha << (s.isCycle(&node1) ? '1' : '0');
    return 0;
}
